#include <stdio.h>

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

void solve() {
    int n;
    scanf("%d", &n);

    int numbers[n]; // Declare an array to hold the input numbers

    for (int i = 0; i < n; i++) {
        scanf("%d", &numbers[i]);
    }

    // Calculate the GCD of the first two numbers
    int g = gcd(numbers[0], numbers[1]);
    for (int i = 2; i < n; i++) {
        g = gcd(g, numbers[i]);
    }

    // Output the result
    for (int i = 0; i < n; i++) {
        printf("%d ", numbers[i] / g);
    }
    printf("\n");
}

int main() {
    int t;
    scanf("%d", &t);
    for (int it = 1; it <= t; it++) {
        solve();
    }
    return 0;
}

