const readline = require('readline');

// Function to calculate GCD
function gcd(a, b) {
    return b === 0 ? a : gcd(b, a % b);
}

// Main function to solve the problem
function solve() {
    // Read input from the command line
    const input = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let lines = [];
    input.on('line', (line) => {
        lines.push(line);
    });

    input.on('close', () => {
        const t = parseInt(lines[0]); // Number of test cases
        let results = [];

        let index = 1;
        for (let i = 0; i < t; i++) {
            const numbers = lines[index].split(' ').map(Number);
            const n = numbers[0]; // The first number is n
            const nums = numbers.slice(1); // Remaining numbers

            // Calculate the GCD of all numbers in the list
            let g = nums[0];
            for (let j = 1; j < n; j++) {
                g = gcd(g, nums[j]);
            }

            // Print the result by dividing each number by the GCD
            results.push(nums.map(num => num / g).join(' '));
            index++;
        }

        console.log(results.join('\n')); // Print all results for each test case
    });
}

// Start the program
solve();
